// --- Helper functions ---

func envLabel(env config.Environment) string {
	return env.Label()
}

func envColor(env config.Environment) string {
	switch env.Stage() {
	case "production":
		return "text-red-400"
	case "staging":
		return "text-yellow-400"
	case "development":
		return "text-emerald-400"
	case "local":
		return "text-sky-400"
	default:
		return "text-white"
	}
}

func driverLabel(driver string) string {
	switch driver {
	case "sqlite":
		return "SQLite"
	case "mysql":
		return "MySQL"
	case "postgres":
		return "PostgreSQL"
	default:
		if driver == "" {
			return "SQLite"
		}
		return driver
	}
}

func formatLabel(format string) string {
	switch format {
	case "contentful":
		return "Contentful"
	case "sanity":
		return "Sanity"
	case "strapi":
		return "Strapi"
	case "wordpress":
		return "WordPress"
	case "clean":
		return "Clean"
	case "raw", "":
		return "Raw"
	default:
		return format
	}
}

func pluginSummaryText(data DashboardData) string {
	if len(data.Plugins) == 0 {
		return "no plugins"
	}
	return fmt.Sprintf("%d running, %d failed", data.PluginsRunning, data.PluginsFailed)
}

func deployText(targets int) string {
	if targets == 0 {
		return ""
	}
	if targets == 1 {
		return "1 target"
	}
	return fmt.Sprintf("%d targets", targets)
}

